**优先级**: 🟡 P1 | **预计工作量**: 2 天

**实施方案**:

```typescript
// src/dashboard/utils/encryption.ts
import { createCipher, createDecipher, randomBytes } from 'crypto'

export class DataEncryption {
  private static algorithm = 'aes-256-gcm'
  private static keyLength = 32
  private static ivLength = 16
  private static saltLength = 64
  private static tagLength = 16

  // 加密数据
  static encrypt(text: string, key: string): string {
    const salt = randomBytes(this.saltLength)
    const iv = randomBytes(this.ivLength)
    const derivedKey = this.deriveKey(key, salt)

    const cipher = createCipher(this.algorithm, derivedKey)
    cipher.setIV(iv)

    let encrypted = cipher.update(text, 'utf8', 'hex')
    encrypted += cipher.final('hex')

    const authTag = cipher.getAuthTag()

    // 组合: salt + iv + authTag + encrypted
    return Buffer.concat([
      salt,
      iv,
      authTag,
      Buffer.from(encrypted, 'hex')
    ]).toString('base64')
  }

  // 解密数据
  static decrypt(encryptedData: string, key: string): string {
    const buffer = Buffer.from(encryptedData, 'base64')

    const salt = buffer.slice(0, this.saltLength)
    const iv = buffer.slice(this.saltLength, this.saltLength + this.ivLength)
    const authTag = buffer.slice(
      this.saltLength + this.ivLength,
      this.saltLength + this.ivLength + this.tagLength
    )
    const encrypted = buffer.slice(this.saltLength + this.ivLength + this.tagLength)

    const derivedKey = this.deriveKey(key, salt)

    const decipher = createDecipher(this.algorithm, derivedKey)
    decipher.setIV(iv)
    decipher.setAuthTag(authTag)

    let decrypted = decipher.update(encrypted)
    decrypted += decipher.final('utf8')

    return decrypted
  }

  // 密钥派生
  private static deriveKey(password: string, salt: Buffer): Buffer {
    const crypto = require('crypto')
    return crypto.pbkdf2Sync(
      password,
      salt,
      100000, // 迭代次数
      this.keyLength,
      'sha256'
    )
  }
}

// 使用示例
export class SecureStorage {
  static setItem(key: string, value: string, encryptionKey: string) {
    const encrypted = DataEncryption.encrypt(value, encryptionKey)
    localStorage.setItem(key, encrypted)
  }

  static getItem(key: string, encryptionKey: string): string | null {
    const encrypted = localStorage.getItem(key)
    if (!encrypted) return null

    try {
      return DataEncryption.decrypt(encrypted, encryptionKey)
    } catch {
      return null
    }
  }
}
