**优先级**: 🟡 P1 | **预计工作量**: 1 天

```typescript
// src/dashboard/middleware/rate-limit.middleware.ts
import { FastifyRequest, FastifyReply } from 'fastify'

interface RateLimitConfig {
  windowMs: number
  maxRequests: number
}

export class RateLimiter {
  private requests: Map<string, number[]> = new Map()

  constructor(private config: RateLimitConfig) {}

  check(identifier: string): boolean {
    const now = Date.now()
    const windowStart = now - this.config.windowMs

    let timestamps = this.requests.get(identifier) || []

    // 清理过期时间戳
    timestamps = timestamps.filter(t => t > windowStart)

    if (timestamps.length >= this.config.maxRequests) {
      return false
    }

    timestamps.push(now)
    this.requests.set(identifier, timestamps)
    return true
  }

  reset(identifier: string) {
    this.requests.delete(identifier)
  }
}

// 中间件工厂
export function createRateLimiter(config: RateLimitConfig) {
  const limiter = new RateLimiter(config)

  return async (request: FastifyRequest, reply: FastifyReply) => {
    const identifier = request.ip || request.headers['x-forwarded-for'] as string

    if (!limiter.check(identifier)) {
      return reply.status(429).send({
        error: 'Too Many Requests',
        message: `Rate limit exceeded. Max ${config.maxRequests} requests per ${config.windowMs}ms.`
      })
    }
  }
}

// 使用示例
export const ipRateLimiter = createRateLimiter({
  windowMs: 60000, // 1 分钟
  maxRequests: 100
})

export const authRateLimiter = createRateLimiter({
  windowMs: 900000, // 15 分钟
  maxRequests: 5 // 登录接口更严格
})
