// 3. 创建认证路由
// src/dashboard/routes/auth.routes.ts

export async function registerAuthRoutes(fastify: any, authService: AuthService) {
  // 登录
  fastify.post('/auth/login', async (request, reply) => {
    const { username, password } = request.body;

    // 验证用户
    const user = await validateUser(username, password);
    if (!user) {
      return reply.status(401).send({
        success: false,
        error: { message: 'Invalid credentials', code: 'INVALID_CREDENTIALS' }
      });
    }

    // 生成令牌
    const accessToken = authService.generateAccessToken(user.id, user.role);
    const refreshToken = authService.generateRefreshToken(user.id);

    return {
      success: true,
      data: {
        accessToken,
        refreshToken,
        user: { id: user.id, username: user.username, role: user.role }
      }
    };
  });

  // 刷新令牌
  fastify.post('/auth/refresh', async (request, reply) => {
    const { refreshToken } = request.body;

    try {
      const decoded = authService.verifyToken(refreshToken);
      const newAccessToken = authService.generateAccessToken(decoded.userId, decoded.role);

      return {
        success: true,
        data: { accessToken: newAccessToken }
      };
    } catch (error) {
      return reply.status(401).send({
        success: false,
        error: { message: 'Invalid refresh token', code: 'INVALID_REFRESH_TOKEN' }
      });
    }
  });

  // 登出
  fastify.post('/auth/logout', {
    onRequest: [authMiddleware]
  }, async (request, reply) => {
    // 将令牌加入黑名单
    await addToBlacklist(request.headers.authorization);

    return {
      success: true,
      message: 'Logged out successfully'
    };
  });
}
