```typescript
// src/dashboard/services/websocket-validator.ts

export class WebSocketValidator {
  /**
   * 验证消息格式
   */
  validateMessage(data: any): { valid: boolean; error?: string } {
    // 基本结构验证
    if (!data || typeof data !== 'object') {
      return { valid: false, error: 'Invalid message format' };
    }

    // 消息大小限制
    const messageSize = JSON.stringify(data).length;
    if (messageSize > 10240) { // 10KB
      return { valid: false, error: 'Message too large' };
    }

    // 事件类型验证
    const validEvents = ['subscribe', 'unsubscribe', 'control', 'ping', 'pong'];
    if (data.event && !validEvents.includes(data.event)) {
      return { valid: false, error: 'Invalid event type' };
    }

    return { valid: true };
  }

  /**
   * 消息速率限制
   */
  private messageCount = new Map<any, number[]>();

  checkRateLimit(socket: any, maxMessages: number = 100, windowMs: number = 60000): boolean {
    const now = Date.now();
    const messages = this.messageCount.get(socket) || [];

    // 清理过期记录
    const recentMessages = messages.filter(time => now - time < windowMs);

    if (recentMessages.length >= maxMessages) {
      return false;
    }

    recentMessages.push(now);
    this.messageCount.set(socket, recentMessages);
    return true;
  }
}

// 使用
connection.socket.on('message', (message) => {
  try {
    const data = JSON.parse(message.toString());

    // 验证消息
    const validation = validator.validateMessage(data);
    if (!validation.valid) {
      connection.socket.send(JSON.stringify({
        event: 'error',
        data: { message: validation.error }
      }));
      return;
    }

    // 速率限制
    if (!validator.checkRateLimit(connection.socket)) {
      connection.socket.send(JSON.stringify({
        event: 'error',
        data: { message: 'Rate limit exceeded' }
      }));
      return;
    }

    handleWebSocketAction(data, connection.socket);
  } catch (error) {
    logger.error(error, 'Failed to parse WebSocket message');
  }
});
