// src/dashboard/services/database.service.ts

export class DatabaseService {
  /**
   * 安全的查询执行（使用参数化）
   */
  safeQuery(sql: string, params: any[] = []) {
    // Better-sqlite3 自动参数化，但仍需验证
    if (!this.isValidSQL(sql)) {
      throw new Error('Invalid SQL query');
    }

    return this.db.prepare(sql).all(...params);
  }

  /**
   * SQL 注入检测
   */
  private isValidSQL(sql: string): boolean {
    // 危险关键词检测
    const dangerous = [
      /\b(DROP|DELETE|TRUNCATE|ALTER)\b/i,
      /\b(EXEC|EXECUTE)\b/i,
      /--/,
      /\/\*/,
      /\;\s*DELETE/,
      /\;\s*DROP/
    ];

    return !dangerous.some(pattern => pattern.test(sql));
  }
}
