// src/dashboard/services/security-logger.ts

export class SecurityLogger {
  /**
   * 记录安全事件
   */
  logSecurityEvent(event: {
    type: 'auth_failure' | 'auth_success' | 'permission_denied' | 'suspicious_activity';
    userId?: string;
    ip: string;
    userAgent: string;
    details: any;
  }) {
    logger.warn({
      event_type: event.type,
      user_id: event.userId,
      ip: this.sanitizeIP(event.ip),
      user_agent: this.sanitizeUserAgent(event.userAgent),
      details: this.sanitizeDetails(event.details),
      timestamp: new Date().toISOString()
    }, 'Security event');
  }

  /**
   * IP 地址脱敏
   */
  private sanitizeIP(ip: string): string {
    const parts = ip.split('.');
    if (parts.length === 4) {
      return `${parts[0]}.${parts[1]}.***.***`;
    }
    return '***';
  }

  /**
   * User Agent 脱敏
   */
  private sanitizeUserAgent(ua: string): string {
    return ua.substring(0, 100);
  }

  /**
   * 敏感信息过滤
   */
  private sanitizeDetails(details: any): any {
    const sensitiveKeys = ['password', 'token', 'secret', 'key'];
    const sanitized = { ...details };

    for (const key of sensitiveKeys) {
      if (sanitized[key]) {
        sanitized[key] = '***REDACTED***';
      }
    }

    return sanitized;
  }
}

// 使用示例
