```typescript
// src/dashboard/services/encrypted-database.service.ts

import Database from 'better-sqlite3';
import crypto from 'crypto';

export class EncryptedDatabaseService {
  private db: Database.Database;
  private encryptionKey: Buffer;

  constructor(dbPath: string, encryptionKey: string) {
    this.encryptionKey = crypto.scryptSync(encryptionKey, 'salt', 32);
    this.db = new Database(dbPath);

    // 启用加密
    this.enableEncryption();
  }

  /**
   * 加密敏感字段
   */
  encrypt(text: string): string {
    const iv = crypto.randomBytes(16);
    const cipher = crypto.createCipheriv('aes-256-cbc', this.encryptionKey, iv);

    let encrypted = cipher.update(text, 'utf8', 'hex');
    encrypted += cipher.final('hex');

    return `${iv.toString('hex')}:${encrypted}`;
  }

  /**
   * 解密敏感字段
   */
  decrypt(encryptedText: string): string {
    const [ivHex, encrypted] = encryptedText.split(':');
    const iv = Buffer.from(ivHex, 'hex');

    const decipher = crypto.createDecipheriv('aes-256-cbc', this.encryptionKey, iv);

    let decrypted = decipher.update(encrypted, 'hex', 'utf8');
    decrypted += decipher.final('utf8');

    return decrypted;
  }

  /**
   * 加密数据库文件
   */
  private enableEncryption() {
    // 使用 SQLCipher 扩展
    this.db.pragma('key = ' + this.encryptionKey.toString('hex'));
    this.db.pragma('cipher_page_size = 4096');
  }
}
