```typescript
// src/dashboard/services/backup.service.ts

import fs from 'fs';
import path from 'path';
import { exec } from 'child_process';

export class BackupService {
  /**
   * 创建数据库备份
   */
  async createBackup(dbPath: string): Promise<string> {
    const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
    const backupPath = path.join(
      path.dirname(dbPath),
      `backups`,
      `backup-${timestamp}.db`
    );

    // 确保备份目录存在
    fs.mkdirSync(path.dirname(backupPath), { recursive: true });

    // 复制数据库文件
    fs.copyFileSync(dbPath, backupPath);

    // 压缩备份
    await this.compressBackup(backupPath);

    logger.info(`Database backup created: ${backupPath}`);
    return backupPath;
  }

  /**
   * 压缩备份文件
   */
  private async compressBackup(filePath: string): Promise<void> {
    return new Promise((resolve, reject) => {
      exec(`gzip "${filePath}"`, (error) => {
        if (error) reject(error);
        else resolve();
      });
    });
  }

  /**
   * 定期备份
   */
  scheduleBackup(dbPath: string, intervalMs: number = 24 * 60 * 60 * 1000) {
    setInterval(async () => {
      try {
        await this.createBackup(dbPath);
      } catch (error) {
        logger.error(error, 'Backup failed');
      }
    }, intervalMs);
  }
}
