## ⚠️ 高优先级问题 (P1)

### 4. SQL 注入风险（部分查询）
**位置**: `src/dashboard/models/index.ts:272-298`  
**严重程度**: 🟠 **中等-高**

**问题描述**:
- `buildFilterConditions` 函数使用了 LIKE 查询，但未对通配符进行转义
- 可能导致通配符注入攻击

**代码证据**:
```typescript
// src/dashboard/models/index.ts:285-287
} else if (typeof value === 'string' && value.includes('%')) {
  conditions.push(`${key} LIKE ?`);
  params.push(value);  // 未验证通配符位置
}
```

**修复建议**:
```typescript
import sqlstring from 'sqlstring';

// 1. 转义 LIKE 通配符
function escapeLike(value: string): string {
  return value
    .replace(/\\/g, '\\\\')   // 转义反斜杠
    .replace(/%/g, '\\%')     // 转义百分号
    .replace(/_/g, '\\_');    // 转义下划线
}

// 2. 限制通配符只能出现在末尾
function validateLikePattern(value: string): boolean {
  const validPattern = /^[^%_]+[%]?$/;
  return validPattern.test(value);
}

// 3. 使用参数化查询
export function buildFilterConditions(
  filter: Record<string, any>
): { sql: string; params: any[] } {
  const conditions: string[] = [];
  const params: any[] = [];

  for (const [key, value] of Object.entries(filter)) {
    if (value === undefined || value === null) continue;

    // 验证列名（白名单）
    const allowedColumns = ['status', 'agent_name', 'started_at'];
    if (!allowedColumns.includes(key)) {
      throw new Error(`Invalid column: ${key}`);
    }

    if (typeof value === 'string' && value.includes('%')) {
      if (!validateLikePattern(value)) {
        throw new Error(`Invalid LIKE pattern: ${value}`);
      }
      conditions.push(`${key} LIKE ? ESCAPE '\\'`);
      params.push(escapeLike(value));
    }
    // ...
  }
  return { sql: conditions.join(' AND ') || '1=1', params };
}
```

