// 使用 SQLCipher 加密数据库
export function initDatabase(dbPath: string, encryptionKey?: string): Database.Database {
  const db = new Database(dbPath);

  if (encryptionKey) {
    // 启用加密
    db.pragma(`key = '${encryptionKey}'`);
    db.pragma('cipher_page_size = 4096');
