class AuditService {
  constructor(private db: Database) {}

  log(action: string, userId: string, resource: string, details: any) {
    this.db.prepare(`
      INSERT INTO audit_logs (action, user_id, resource, details, ip_address, user_agent, timestamp)
      VALUES (?, ?, ?, ?, ?, ?, ?)
    `).run(
      action,
      userId,
      resource,
