**2.1 实现 JWT 认证**
```typescript
// src/dashboard/middleware/auth.ts
import jwt from 'jsonwebtoken';

const JWT_SECRET = process.env.JWT_SECRET || 'your-secret-key-change-in-production';

export interface JWTPayload {
  userId: string;
  role: 'admin' | 'user' | 'viewer';
}

export async function authenticateToken(request: any, reply: any) {
  const authHeader = request.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) {
    return reply.code(401).send({ error: 'Access token required' });
  }

  try {
    const decoded = jwt.verify(token, JWT_SECRET) as JWTPayload;
    request.user = decoded;
  } catch (error) {
    return reply.code(403).send({ error: 'Invalid or expired token' });
  }
}

export function requireRole(roles: string[]) {
  return async (request: any, reply: any) => {
    if (!request.user) {
      return reply.code(401).send({ error: 'Unauthorized' });
    }

    if (!roles.includes(request.user.role)) {
      return reply.code(403).send({ error: 'Forbidden' });
    }
  };
}
```

**2.2 添加认证路由**
```typescript
// src/dashboard/routes/auth.ts
import bcrypt from 'bcrypt';
import jwt from 'jsonwebtoken';

// 用户模型（简化版）
const users = [
  {
    id: '1',
    username: 'admin',
    passwordHash: '$2b$10$...',  // bcrypt hash
    role: 'admin'
  }
];

// 登录
fastify.post('/auth/login', async (request, reply) => {
  const { username, password } = request.body;

  const user = users.find(u => u.username === username);
  if (!user) {
    return reply.code(401).send({ error: 'Invalid credentials' });
  }

  const isValid = await bcrypt.compare(password, user.passwordHash);
  if (!isValid) {
    return reply.code(401).send({ error: 'Invalid credentials' });
  }

  const token = jwt.sign(
    { userId: user.id, role: user.role },
    process.env.JWT_SECRET,
    { expiresIn: '24h' }
  );

  return reply.send({ token, user: { id: user.id, role: user.role } });
});

// 注册（首次运行时创建管理员）
fastify.post('/auth/register', async (request, reply) => {
  const { username, password } = request.body;

  // 检查是否已有用户
  if (users.length > 0) {
    return reply.code(403).send({ error: 'Registration disabled' });
  }

  const passwordHash = await bcrypt.hash(password, 10);
  const user = {
    id: Date.now().toString(),
    username,
    passwordHash,
    role: 'admin'
  };

  users.push(user);

  return reply.code(201).send({ message: 'Admin user created' });
});
```

