### 3. Git 命令注入风险

**位置**: `src/auto-iteration.ts:328-352`

```typescript
// ⚠️ 当前代码
const prevCommit = childProcess.execSync(
  'git rev-parse --short HEAD', 
  { cwd, encoding: 'utf-8' }
).trim();

childProcess.execSync(`git commit -m "${commitMessage}"`, { cwd });
// 🔴 commitMessage 未验证,可能包含命令注入!
```

**风险**:
- 如果 commitMessage 包含 `"; rm -rf /;`
- 可能执行任意 shell 命令
- 攻击者可以破坏系统

**修复建议**:

```typescript
// ✅ 推荐方案
import { execFileSync } from 'child_process';

// 1. 使用 execFileSync 而非 execSync (更安全)
// 2. 将参数作为数组传递 (避免 shell 解析)
function safeGitCommand(cwd: string, command: string, args: string[]): string {
  try {
    const result = execFileSync('git', [command, ...args], {
      cwd,
      encoding: 'utf-8',
      env: { ...process.env, GIT_TERMINAL_PROMPT: '0' }
    });
    return result.trim();
  } catch (error) {
    throw new Error(`Git command failed: ${command}`);
  }
}

// 3. 验证和清理 commitMessage
function sanitizeCommitMessage(message: string): string {
  // 移除危险字符
  const cleaned = message
    .replace(/[^a-zA-Z0-9\u4e00-\u9fa5\s\-_.,!?]/g, '')
    .substring(0, 72); // Git 限制

  if (cleaned !== message) {
    logger.warn({ original: message, cleaned }, 'Commit message sanitized');
  }

  return cleaned;
}

// 4. 使用安全的方式执行
const safeMessage = sanitizeCommitMessage(commitMessage);
safeGitCommand(cwd, 'commit', ['-m', safeMessage]);
```

