// ✅ 安装速率限制插件
import rateLimit from '@fastify/rate-limit';

await server.register(rateLimit, {
  max: 100,      // 每分钟最多 100 个请求
  timeWindow: '1 minute',
  allowList: ['127.0.0.1'],  // 本地不限制
  skipOnError: true,
  addHeaders: {
    'x-ratelimit-limit': true,
    'x-ratelimit-remaining': true,
    'x-ratelimit-retry-after': true
  }
});

// WebSocket 也需要限制
const wsRateLimiter = new Map();
function checkWSRateLimit(clientId: string): boolean {
  const now = Date.now();
  const clientData = wsRateLimiter.get(clientId) || { count: 0, resetAt: now + 60000 };

  if (now > clientData.resetAt) {
    clientData.count = 0;
    clientData.resetAt = now + 60000;
  }

  if (clientData.count > 60) {  // 每分钟 60 个消息
    return false;
  }

  clientData.count++;
  wsRateLimiter.set(clientId, clientData);
  return true;
}
```

