```typescript
// ✅ 1. 数据库加密
import { Database } from 'better-sqlite3';
import sqljs from 'sql.js';

// 2. 敏感字段加密
import crypto from 'crypto';

const ENCRYPTION_KEY = process.env.DB_ENCRYPTION_KEY; // 32 字节密钥
const IV_LENGTH = 16;

function encrypt(text: string): string {
  const iv = crypto.randomBytes(IV_LENGTH);
  const cipher = crypto.createCipheriv('aes-256-cbc', Buffer.from(ENCRYPTION_KEY), iv);

  let encrypted = cipher.update(text, 'utf8', 'hex');
  encrypted += cipher.final('hex');

  return iv.toString('hex') + ':' + encrypted;
}

function decrypt(text: string): string {
  const parts = text.split(':');
  const iv = Buffer.from(parts[0], 'hex');
  const encrypted = parts[1];

  const decipher = crypto.createDecipheriv('aes-256-cbc', Buffer.from(ENCRYPTION_KEY), iv);

  let decrypted = decipher.update(encrypted, 'hex', 'utf8');
  decrypted += decipher.final('utf8');

  return decrypted;
}

// 3. 数据库权限设置
import { chmod } from 'fs/promises';

await chmod(config.databasePath, 0o600);  // 仅所有者可读写

// 4. 定期备份
import { copyFile } from 'fs/promises';

async function backupDatabase() {
  const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
  const backupPath = `${config.databasePath}.backup.${timestamp}`;
  await copyFile(config.databasePath, backupPath);

  // 只保留最近 7 天的备份
  await cleanOldBackups(config.databasePath, 7);
}

setInterval(backupDatabase, 24 * 60 * 60 * 1000);  // 每天备份
