#### 阶段 3: WebSocket 服务 (Day 4)

**`src/services/websocket.ts`**:
```typescript
import { ref } from 'vue';

export interface WSMessage {
  event: string;
  data: any;
  timestamp: string;
}

export function useWebSocket() {
  const ws = ref<WebSocket | null>(null);
  const reconnectTimer = ref<number>();
  const reconnectAttempts = ref(0);
  const MAX_RECONNECT_ATTEMPTS = 5;

  function connect() {
    const wsUrl = `ws://localhost:3000/api/ws`;
    ws.value = new WebSocket(wsUrl);

    ws.value.onopen = () => {
      console.log('✅ WebSocket connected');
      reconnectAttempts.value = 0;
    };

    ws.value.onmessage = (event) => {
      try {
        const message: WSMessage = JSON.parse(event.data);
        handleMessage(message);
      } catch (error) {
        console.error('Failed to parse WebSocket message:', error);
      }
    };

    ws.value.onclose = () => {
      console.log('❌ WebSocket disconnected');
      scheduleReconnect();
    };

    ws.value.onerror = (error) => {
      console.error('WebSocket error:', error);
    };
  }

  function scheduleReconnect() {
    if (reconnectAttempts.value >= MAX_RECONNECT_ATTEMPTS) {
      console.error('Max reconnect attempts reached');
      return;
    }

    const delay = Math.min(1000 * Math.pow(2, reconnectAttempts.value), 30000);
    reconnectAttempts.value++;

    reconnectTimer.value = window.setTimeout(() => {
      console.log(`Reconnecting... (attempt ${reconnectAttempts.value})`);
      connect();
    }, delay);
  }

  function disconnect() {
    if (reconnectTimer.value) {
      clearTimeout(reconnectTimer.value);
    }
    if (ws.value) {
      ws.value.close();
      ws.value = null;
    }
  }

  function onMessage(callback: (message: WSMessage) => void) {
    // 在组件中使用 Pinia store 管理回调
  }

  function send(event: string, data: any) {
    if (ws.value?.readyState === WebSocket.OPEN) {
      ws.value.send(JSON.stringify({ event, data }));
    }
  }

  return {
    connect,
    disconnect,
    send,
    onMessage
  };
}
```

