// src/dashboard/routes/iterations.ts
export async function iterationRoutes(fastify: FastifyInstance) {
  // GET /api/iterations - 获取迭代列表
  fastify.get('/', async (request, reply) => {
    const { page = 1, limit = 20, status } = request.query as any;

    const iterations = await iterationService.list({
      page: Number(page),
      limit: Number(limit),
      status
    });

    return reply.send(iterations);
  });

  // GET /api/iterations/:id - 获取迭代详情
  fastify.get('/:id', async (request, reply) => {
    const { id } = request.params as { id: string };
    const iteration = await iterationService.getById(Number(id));

    if (!iteration) {
      return reply.code(404).send({ error: 'Iteration not found' });
    }

    return reply.send(iteration);
  });

  // POST /api/iterations/:id/rollback - 回滚迭代
  fastify.post('/:id/rollback', async (request, reply) => {
    const { id } = request.params as { id: string };

    // ✅ 添加权限检查
    if (!request.user?.permissions?.includes('rollback')) {
      return reply.code(403).send({ error: 'Forbidden' });
    }

    try {
      const result = await iterationService.rollback(Number(id));
      return reply.send(result);
    } catch (error) {
      return reply.code(500).send({ error: error.message });
    }
  });

  // GET /api/iterations/current - 获取当前运行迭代
  fastify.get('/current', async (request, reply) => {
    const current = await iterationService.getCurrent();
    return reply.send(current || { status: 'idle' });
  });
}
