export class AutoIterationEngine {
  private dashboardServices?: any;

  async initializeDashboard() {
    try {
      // 动态导入 Dashboard 服务
      const dashboardModule = await import('./dashboard/server');
      this.dashboardServices = dashboardModule.getServices();

      console.log('✅ Dashboard services connected');
