    if (!this.dashboardServices) {
      return;
    }

    const { realtimeService, iterationService } = this.dashboardServices;

    switch (event) {
      case 'iteration.started':
        await iterationService.create({
          iterationNumber: this.count,
          status: 'running',
          requirement: this.requirement
        });
        realtimeService.broadcastIterationStatusChange(data);
        break;

      case 'iteration.phase_changed':
        realtimeService.broadcastIterationProgress(data);
        break;

      case 'agent.status_changed':
        realtimeService.broadcastAgentStatusChange(data);
        break;

      case 'iteration.completed':
        await iterationService.update(this.currentIterationId, {
          status: 'completed',
          completedAt: new Date()
        });
        realtimeService.broadcastIterationStatusChange(data);
        break;

      case 'iteration.failed':
        await iterationService.update(this.currentIterationId, {
          status: 'failed',
          error: data.error
        });
        realtimeService.broadcastIterationStatusChange(data);
        break;
    }
  }

