// src/utils/retry.ts
export class RetryManager {
  private maxRetries: number;
  private baseDelay: number;
  private maxDelay: number;

  constructor(options: { maxRetries?: number; baseDelay?: number; maxDelay?: number } = {}) {
    this.maxRetries = options.maxRetries ?? 3;
    this.baseDelay = options.baseDelay ?? 1000;
    this.maxDelay = options.maxDelay ?? 10000;
  }

  async retry<T>(
    fn: () => Promise<T>,
    context: { operation: string; agent?: string }
  ): Promise<T> {
    let lastError: Error;

    for (let attempt = 0; attempt <= this.maxRetries; attempt++) {
      try {
        return await fn();
      } catch (error) {
        lastError = error;

        if (attempt === this.maxRetries) {
          throw new Error(
            `${context.operation} failed after ${this.maxRetries} retries: ${error.message}`
          );
        }

        const delay = Math.min(
          this.baseDelay * Math.pow(2, attempt),
          this.maxDelay
        );

        console.warn(
          `Retry ${attempt + 1}/${this.maxRetries} for ${context.operation} after ${delay}ms`
        );

        await this.sleep(delay);
      }
    }

    throw lastError!;
  }

  private sleep(ms: number): Promise<void> {
    return new Promise(resolve => setTimeout(resolve, ms));
  }
}

// 使用示例
const retryManager = new RetryManager({ maxRetries: 3 });

const result = await retryManager.retry(
  () => backendAgent.executeAndCollect(prompt),
