// src/monitoring/performance-monitor.ts
export class PerformanceMonitor {
  private metrics: Map<string, number[]> = new Map();

  recordExecutionTime(agent: string, phase: string, duration: number) {
    const key = `${agent}.${phase}`;

    if (!this.metrics.has(key)) {
      this.metrics.set(key, []);
    }

    this.metrics.get(key)!.push(duration);
  }

  getStats(agent: string, phase: string) {
    const key = `${agent}.${phase}`;
    const times = this.metrics.get(key) || [];

    if (times.length === 0) {
      return null;
    }

    const sorted = [...times].sort((a, b) => a - b);

    return {
      count: times.length,
      min: sorted[0],
      max: sorted[sorted.length - 1],
      avg: times.reduce((a, b) => a + b, 0) / times.length,
      p50: sorted[Math.floor(sorted.length * 0.5)],
      p95: sorted[Math.floor(sorted.length * 0.95)],
      p99: sorted[Math.floor(sorted.length * 0.99)]
    };
  }

  getAllStats() {
    const stats: Record<string, any> = {};

    for (const [key, times] of this.metrics.entries()) {
      const [agent, phase] = key.split('.');
      stats[key] = this.getStats(agent, phase);
    }

    return stats;
  }
}
