// src/utils/logger.ts
import pino from 'pino';
import path from 'path';

const logLevels = ['fatal', 'error', 'warn', 'info', 'debug', 'trace'];

// 创建敏感数据过滤器
const sensitiveKeys = [
  'password',
  'token',
  'apiKey',
  'secret',
  'authorization'
];

function redactSensitiveData(data: any): any {
  if (typeof data === 'string') {
    return data.replace(/Bearer\s+[A-Za-z0-9\-._~+/]+=*/g, 'Bearer ***');
  }

  if (typeof data !== 'object' || data === null) {
    return data;
  }

  const sanitized = Array.isArray(data) ? [...data] : { ...data };

  for (const key in sanitized) {
    const lowerKey = key.toLowerCase();

    if (sensitiveKeys.some(sk => lowerKey.includes(sk))) {
      sanitized[key] = '***';
    } else if (typeof sanitized[key] === 'object') {
      sanitized[key] = redactSensitiveData(sanitized[key]);
    }
  }

  return sanitized;
}

export const logger = pino({
  level: process.env.LOG_LEVEL || 'info',
  formatters: {
    level: (label) => {
      return { level: label };
    },
    log: (object) => {
      return redactSensitiveData(object);
    }
  },
  serializers: {
    error: pino.stdSerializers.err,
    req: pino.stdSerializers.req,
    res: pino.stdSerializers.res
  },
  transport: {
    target: 'pino-pretty',
    options: {
      colorize: true,
      translateTime: 'HH:MM:ss',
      ignore: 'pid,hostname',
      singleLine: false
    }
  }
});

// Agent 专用日志器
export function createAgentLogger(agentName: string) {
  return logger.child({ agent: agentName });
}
