### 6. 自动 Git 操作可能泄露敏感信息 🟡

**位置**: `src/auto-iteration.ts:323-361`

```typescript
private async gitCommit(task: string) {
  // ...
  childProcess.execSync('git add .', { cwd });
  childProcess.execSync(`git commit -m "${commitMessage}"`, { cwd });
  childProcess.execSync('git push', { cwd });
}
```

**风险等级**: 🟡 **中等**

**风险描述**:
- `git add .` 可能提交敏感文件（.env、密钥等）
- 自动推送可能导致敏感信息泄露到远程仓库
- 一旦推送，难以从历史记录中清除

**修复建议**:
```typescript
// ✅ 更安全的 Git 操作
private async gitCommit(task: string) {
  const cwd = this.config.projectPath;

  try {
    // 1. 检查是否有 .env 文件被暂存
    const stagedFiles = childProcess.execSync(
      'git diff --cached --name-only',
      { cwd, encoding: 'utf-8' }
    );

    const dangerousFiles = ['.env', '.env.local', '*.secret', '*.key'];
    const hasDangerousFiles = dangerousFiles.some(pattern => 
      stagedFiles.includes(pattern)
    );

    if (hasDangerousFiles) {
      logger.error('⚠️ 检测到敏感文件，取消 Git 提交');
      return null;
    }

    // 2. 使用 .gitignore 确保敏感文件被忽略
    // 确保 .gitignore 包含:
    // .env
    // .env.*
    // *.secret
    // *.key
    // node_modules/

    // 3. 添加预提交 Hook
    // 在 .git/hooks/pre-commit 中检查敏感文件

    // 4. 执行 Git 操作
    childProcess.execSync('git add .', { cwd });
    const commitMessage = `auto: ${task.substring(0, 50)}`;
    childProcess.execSync(`git commit -m "${commitMessage}"`, { cwd });

    // 5. 提交前检查
    const newCommit = childProcess.execSync(
      'git rev-parse --short HEAD',
      { cwd, encoding: 'utf-8' }
    ).trim();

    // 6. 可选: 推送前确认
    if (this.config.autoPush) {
      logger.info('准备推送到远程仓库...');
      // 可以添加人工确认步骤
      childProcess.execSync('git push', { cwd });
      logger.info('✅ 已推送到远程');
    }

    return { commitId: newCommit };
  } catch (error) {
    logger.error('Git 操作失败:', error);
    return null;
  }
}
```

